truncate table public.reports, public.cars;

insert into public.reports (
  line,
  car,
  state,
  created_at,
  review_status
)
select
  line,
  car,
  state,
  created_at,
  'accepted'
from launch_reports;

insert into public.cars (
  code,
  line,
  verified,
  source
)
select distinct
  car,
  line,
  false,
  'launch reports import'
from launch_reports
where car is not null
on conflict (code, line) do update set
  active = true,
  source = excluded.source;
